# Conference calendar tracker
# Save as conf_tracker.py and run with: python conf_tracker.py

import json
from datetime import datetime, date

CONFERENCES = [
    {
        "name": "NeurIPS",
        "url": "https://neurips.cc",
        "type": "academic",
        "approximate_dates": {"paper_deadline": "05-15", "conference": "12-10"},
        "cost_usd": 2000,
        "focus": ["deep learning", "RL", "agents", "LLMs"]
    },
    {
        "name": "ICLR",
        "url": "https://iclr.cc",
        "type": "academic",
        "approximate_dates": {"paper_deadline": "10-01", "conference": "05-01"},
        "cost_usd": 1500,
        "focus": ["representation learning", "LLMs", "agents"]
    },
    {
        "name": "ICML",
        "url": "https://icml.cc",
        "type": "academic",
        "approximate_dates": {"paper_deadline": "01-25", "conference": "07-15"},
        "cost_usd": 1800,
        "focus": ["machine learning", "optimization", "agents"]
    },
    {
        "name": "ACL",
        "url": "https://2025.aclweb.org",
        "type": "academic",
        "approximate_dates": {"paper_deadline": "02-15", "conference": "07-25"},
        "cost_usd": 1200,
        "focus": ["NLP", "dialogue", "tool use", "LLMs"]
    },
    {
        "name": "AI Engineer Summit",
        "url": "https://ai.engineer",
        "type": "practitioner",
        "approximate_dates": {"cfp_deadline": "03-01", "conference": "06-01"},
        "cost_usd": 800,
        "focus": ["LLM engineering", "agents", "production AI"]
    },
]

def upcoming_deadlines(days_ahead: int = 90) -> list[dict]:
    today = date.today()
    year = today.year
    results = []
    for conf in CONFERENCES:
        for deadline_type, date_str in conf["approximate_dates"].items():
            deadline = date(year, int(date_str.split("-")[0]), int(date_str.split("-")[1]))
            days_until = (deadline - today).days
            if 0 <= days_until <= days_ahead:
                results.append({
                    "conference": conf["name"],
                    "type": deadline_type,
                    "date": str(deadline),
                    "days_until": days_until,
                    "url": conf["url"]
                })
    return sorted(results, key=lambda x: x["days_until"])

if __name__ == "__main__":
    upcoming = upcoming_deadlines(90)
    if not upcoming:
        print("No deadlines in the next 90 days.")
    else:
        print(f"Upcoming conference deadlines (next 90 days):\n")
        for item in upcoming:
            print(f"  {item['days_until']:3d} days — {item['conference']} {item['type']}: {item['date']}")
            print(f"         {item['url']}")
